export type VoiceName = 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';

export enum AudioStatus {
  IDLE = 'idle',
  PROCESSING = 'processing',
  COMPLETED = 'completed',
  FAILED = 'failed'
}

export interface Segment {
  id: string;
  name: string;
  text: string;
  status: AudioStatus;
  audioBlob?: Blob;
  error?: string;
  progress?: number;
}

export interface GenerationSettings {
  voice: VoiceName;
  speed: number;
  pitch: number;
  emotion: string;
  language: string;
}

export interface VoiceOption {
  id: string;
  name: string;
  gender: 'male' | 'female';
  baseVoice: VoiceName;
  description: string;
}

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function pcmToWav(pcmData: Uint8Array, sampleRate: number = 24000, numChannels: number = 1): Promise<Blob> {
  const dataLen = pcmData.length;
  const buffer = new ArrayBuffer(44 + dataLen);
  const view = new DataView(buffer);

  // Write WAV header
  const writeString = (offset: number, string: string) => {
    for (let i = 0; i < string.length; i++) {
      view.setUint8(offset + i, string.charCodeAt(i));
    }
  };

  writeString(0, 'RIFF');
  view.setUint32(4, 36 + dataLen, true);
  writeString(8, 'WAVE');
  writeString(12, 'fmt ');
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true); // PCM format
  view.setUint16(22, numChannels, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * numChannels * 2, true);
  view.setUint16(32, numChannels * 2, true);
  view.setUint16(34, 16, true); // 16 bits per sample
  writeString(36, 'data');
  view.setUint32(40, dataLen, true);

  // Write PCM samples
  const pcmView = new Uint8Array(buffer, 44);
  pcmView.set(pcmData);

  return new Blob([buffer], { type: 'audio/wav' });
}

export async function mergeAudioBlobs(blobs: Blob[]): Promise<Blob> {
  // Simple concatenation for now, as they share the same format.
  // Real audio merging should ideally re-encode to ensure no header issues, 
  // but for raw PCM encoded as WAV with same parameters, it usually works if we strip headers.
  // To be safe, we'll just concatenate the data parts.

  const headers = [];
  const datas = [];

  for (const blob of blobs) {
    const arrayBuffer = await blob.arrayBuffer();
    // Assuming 44 byte header for all
    datas.push(arrayBuffer.slice(44));
    if (headers.length === 0) {
      headers.push(arrayBuffer.slice(0, 44));
    }
  }

  const totalDataSize = datas.reduce((acc, d) => acc + d.byteLength, 0);
  const finalBuffer = new Uint8Array(44 + totalDataSize);

  // Header
  const firstHeader = new DataView(headers[0]);
  firstHeader.setUint32(4, 36 + totalDataSize, true);
  firstHeader.setUint32(40, totalDataSize, true);
  finalBuffer.set(new Uint8Array(headers[0]), 0);

  // Data
  let offset = 44;
  for (const data of datas) {
    finalBuffer.set(new Uint8Array(data), offset);
    offset += data.byteLength;
  }

  return new Blob([finalBuffer], { type: 'audio/wav' });
}

import { GoogleGenAI, Modality } from "@google/genai";
import { GenerationSettings } from "../types";
import { decodeBase64, pcmToWav } from "../utils/audioUtils";

export async function generateAudioForSegment(
  text: string, 
  settings: GenerationSettings
): Promise<Blob> {
  const apiKey = (process as any).env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing.");

  const ai = new GoogleGenAI({ apiKey });

  // Format prompt with emotion/style
  const styledPrompt = `${settings.emotion !== 'Neutral' ? `Say ${settings.emotion}: ` : ''}${text}`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: styledPrompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: settings.voice },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  if (!base64Audio) {
    throw new Error("No audio data returned from Gemini.");
  }

  const pcmBytes = decodeBase64(base64Audio);
  return await pcmToWav(pcmBytes);
}

export function splitTextIntoSegments(text: string, wordsPerSegment: number = 750): string[] {
  const words = text.trim().split(/\s+/);
  const segments: string[] = [];

  for (let i = 0; i < words.length; i += wordsPerSegment) {
    segments.push(words.slice(i, i + wordsPerSegment).join(" "));
  }

  return segments;
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  AudioStatus, 
  Segment, 
  GenerationSettings, 
  VoiceOption, 
  VoiceName 
} from './types';
import { VOICES, EMOTIONS, LANGUAGES } from './constants.tsx';
import { splitTextIntoSegments, generateAudioForSegment } from './services/geminiService';
import { mergeAudioBlobs } from './utils/audioUtils';

// Standard declaration for external scripts
declare const JSZip: any;

const App: React.FC = () => {
  const [script, setScript] = useState('');
  const [segments, setSegments] = useState<Segment[]>([]);
  const [settings, setSettings] = useState<GenerationSettings>({
    voice: 'Kore',
    speed: 1.0,
    pitch: 1.0,
    emotion: 'Neutral',
    language: 'en-US'
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedVoiceId, setSelectedVoiceId] = useState('v1');
  const [activeTab, setActiveTab] = useState<'input' | 'processing'>('input');

  const processingRef = useRef<boolean>(false);

  const handleSplitScript = () => {
    if (!script.trim()) return;
    const textSegments = splitTextIntoSegments(script);
    const newSegments: Segment[] = textSegments.map((text, index) => ({
      id: `seg-${Date.now()}-${index}`,
      name: `Segment ${index + 1}`,
      text,
      status: AudioStatus.IDLE,
      progress: 0
    }));
    setSegments(newSegments);
    setActiveTab('processing');
  };

  const processAllSegments = async () => {
    if (isProcessing) return;
    setIsProcessing(true);
    processingRef.current = true;

    // Process in batches of 3 to avoid rate limits while maintaining speed
    const batchSize = 3;
    const segmentsToProcess = [...segments];

    for (let i = 0; i < segmentsToProcess.length; i += batchSize) {
      if (!processingRef.current) break;

      const currentBatch = segmentsToProcess.slice(i, i + batchSize);

      await Promise.all(currentBatch.map(async (seg) => {
        if (seg.status === AudioStatus.COMPLETED) return;

        setSegments(prev => prev.map(s => 
          s.id === seg.id ? { ...s, status: AudioStatus.PROCESSING } : s
        ));

        try {
          const audioBlob = await generateAudioForSegment(seg.text, settings);
          setSegments(prev => prev.map(s => 
            s.id === seg.id ? { ...s, status: AudioStatus.COMPLETED, audioBlob } : s
          ));
        } catch (error: any) {
          console.error(`Error processing ${seg.name}:`, error);
          setSegments(prev => prev.map(s => 
            s.id === seg.id ? { ...s, status: AudioStatus.FAILED, error: error.message } : s
          ));
        }
      }));
    }

    setIsProcessing(false);
    processingRef.current = false;
  };

  const stopProcessing = () => {
    processingRef.current = false;
    setIsProcessing(false);
  };

  const handleDownloadZip = async () => {
    const zip = new JSZip();
    const completed = segments.filter(s => s.status === AudioStatus.COMPLETED && s.audioBlob);

    if (completed.length === 0) return;

    completed.forEach(s => {
      zip.file(`${s.name.replace(/\s+/g, '_').toLowerCase()}.wav`, s.audioBlob!);
    });

    const content = await zip.generateAsync({ type: 'blob' });
    const url = URL.createObjectURL(content);
    const a = document.createElement('a');
    a.href = url;
    a.download = `voice_generation_${Date.now()}.zip`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleDownloadMerged = async () => {
    const completed = segments.filter(s => s.status === AudioStatus.COMPLETED && s.audioBlob);
    if (completed.length === 0) return;

    try {
      const mergedBlob = await mergeAudioBlobs(completed.map(s => s.audioBlob!));
      const url = URL.createObjectURL(mergedBlob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `full_narration_${Date.now()}.wav`;
      a.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      alert("Failed to merge audio segments. Try downloading as ZIP.");
    }
  };

  const handleVoiceChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const vId = e.target.value;
    setSelectedVoiceId(vId);
    const voice = VOICES.find(v => v.id === vId);
    if (voice) {
      setSettings(prev => ({ ...prev, voice: voice.baseVoice }));
    }
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <header className="mb-8 text-center">
        <h1 className="text-4xl font-bold text-slate-800 mb-2">Gemini TTS Studio</h1>
        <p className="text-slate-500">Long-form narration made easy with Google AI</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Settings Panel */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
              Settings
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Select Voice</label>
                <select 
                  value={selectedVoiceId}
                  onChange={handleVoiceChange}
                  className="w-full rounded-lg border-slate-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 py-2 px-3 border"
                >
                  {VOICES.map(v => (
                    <option key={v.id} value={v.id}>{v.name} ({v.gender}, {v.description})</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Emotion / Style</label>
                <select 
                  value={settings.emotion}
                  onChange={(e) => setSettings(s => ({ ...s, emotion: e.target.value }))}
                  className="w-full rounded-lg border-slate-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 py-2 px-3 border"
                >
                  {EMOTIONS.map(e => <option key={e} value={e}>{e}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Language</label>
                  <select 
                    value={settings.language}
                    onChange={(e) => setSettings(s => ({ ...s, language: e.target.value }))}
                    className="w-full rounded-lg border-slate-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 py-2 px-3 border text-sm"
                  >
                    {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Batch Size</label>
                  <input type="number" value="3" readOnly className="w-full rounded-lg border-slate-300 shadow-sm bg-slate-50 py-2 px-3 border text-sm cursor-not-allowed" />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
             <h2 className="text-lg font-semibold mb-2">Stats</h2>
             <div className="space-y-2 text-sm text-slate-600">
                <div className="flex justify-between">
                  <span>Total Segments:</span>
                  <span className="font-semibold">{segments.length}</span>
                </div>
                <div className="flex justify-between">
                  <span>Completed:</span>
                  <span className="font-semibold text-green-600">
                    {segments.filter(s => s.status === AudioStatus.COMPLETED).length}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span>Remaining:</span>
                  <span className="font-semibold text-blue-600">
                    {segments.filter(s => s.status === AudioStatus.IDLE || s.status === AudioStatus.PROCESSING).length}
                  </span>
                </div>
             </div>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="lg:col-span-2 space-y-6">
          {/* Tabs */}
          <div className="flex border-b border-slate-200 gap-6">
            <button 
              onClick={() => setActiveTab('input')}
              className={`pb-3 text-sm font-medium transition-colors ${activeTab === 'input' ? 'border-b-2 border-indigo-500 text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              1. Script Input
            </button>
            <button 
              onClick={() => setActiveTab('processing')}
              className={`pb-3 text-sm font-medium transition-colors ${activeTab === 'processing' ? 'border-b-2 border-indigo-500 text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              2. Generation & Export
            </button>
          </div>

          {activeTab === 'input' ? (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col h-[600px]">
              <label className="block text-sm font-medium text-slate-700 mb-2">Paste your long-form script here</label>
              <textarea 
                value={script}
                onChange={(e) => setScript(e.target.value)}
                placeholder="Once upon a time in a galaxy far, far away..."
                className="flex-1 w-full rounded-lg border-slate-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-4 border resize-none mb-4"
              />
              <button 
                onClick={handleSplitScript}
                disabled={!script.trim()}
                className="w-full py-3 bg-indigo-600 text-white rounded-xl font-semibold hover:bg-indigo-700 disabled:opacity-50 transition-colors flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14.121 14.121L19 19m-7-7l7-7m-7 7l-2.879 2.879M12 12L9.121 9.121m0 5.758L5 19m0-14l4.121 4.121"></path></svg>
                Segment Script
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="flex items-center justify-between bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                <div className="flex gap-2">
                  {!isProcessing ? (
                    <button 
                      onClick={processAllSegments}
                      disabled={segments.length === 0}
                      className="px-4 py-2 bg-indigo-600 text-white rounded-lg font-medium hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2"
                    >
                      <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M4.5 3a.5.5 0 00-.5.5v13a.5.5 0 00.757.429l11-6.5a.5.5 0 000-.858l-11-6.5A.5.5 0 004.5 3z" /></svg>
                      Generate All
                    </button>
                  ) : (
                    <button 
                      onClick={stopProcessing}
                      className="px-4 py-2 bg-rose-600 text-white rounded-lg font-medium hover:bg-rose-700 flex items-center gap-2"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1H10a1 1 0 01-1-1v-4z"></path></svg>
                      Stop
                    </button>
                  )}
                </div>

                <div className="flex gap-2">
                  <button 
                    onClick={handleDownloadMerged}
                    disabled={segments.filter(s => s.status === AudioStatus.COMPLETED).length === 0}
                    className="px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg font-medium hover:bg-slate-50 disabled:opacity-50"
                  >
                    Merge & Download
                  </button>
                  <button 
                    onClick={handleDownloadZip}
                    disabled={segments.filter(s => s.status === AudioStatus.COMPLETED).length === 0}
                    className="px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg font-medium hover:bg-slate-50 disabled:opacity-50 flex items-center gap-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                    Download ZIP
                  </button>
                </div>
              </div>

              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="max-h-[500px] overflow-y-auto divide-y divide-slate-100">
                  {segments.length === 0 && (
                    <div className="p-12 text-center text-slate-400">
                      No segments generated. Go back to the "Script Input" tab to segment your text.
                    </div>
                  )}
                  {segments.map((seg, idx) => (
                    <div key={seg.id} className="p-4 hover:bg-slate-50 transition-colors flex items-center justify-between">
                      <div className="flex flex-col min-w-0 pr-4">
                        <span className="font-semibold text-slate-800 text-sm">{seg.name}</span>
                        <p className="text-xs text-slate-500 truncate max-w-md">{seg.text}</p>
                      </div>
                      <div className="flex items-center gap-4 flex-shrink-0">
                        {seg.status === AudioStatus.PROCESSING && (
                          <div className="flex items-center gap-2">
                            <div className="w-4 h-4 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin" />
                            <span className="text-xs text-indigo-600 font-medium">Generating...</span>
                          </div>
                        )}
                        {seg.status === AudioStatus.COMPLETED && seg.audioBlob && (
                          <div className="flex items-center gap-3">
                            <audio src={URL.createObjectURL(seg.audioBlob)} controls className="h-8 w-48" />
                            <span className="text-xs text-green-600 font-medium bg-green-50 px-2 py-1 rounded">Ready</span>
                          </div>
                        )}
                        {seg.status === AudioStatus.FAILED && (
                          <div className="flex flex-col items-end">
                            <span className="text-xs text-rose-600 font-medium">Failed</span>
                            <button 
                              onClick={() => {
                                // Manual retry logic for single segment could go here
                              }}
                              className="text-[10px] text-slate-400 hover:text-indigo-600"
                            >
                              Retry
                            </button>
                          </div>
                        )}
                        {seg.status === AudioStatus.IDLE && (
                          <span className="text-xs text-slate-400 italic">Queued</span>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      <footer className="mt-12 pt-8 border-t border-slate-200 text-center text-slate-400 text-sm">
        <p>Uses Gemini 2.5 Flash Preview TTS for high-fidelity long-form narration.</p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
